Here's a simple C++ program for a calculator:

```cpp
#include <iostream>
using namespace std;

int main() {
    int choice;
    float num1, num2;

    cout << "Simple Calculator" << endl;
    cout << "1. Addition" << endl;
    cout << "2. Subtraction" << endl;
    cout << "3. Multiplication" << endl;
    cout << "4. Division" << endl;

    cout << "Enter your choice (1/2/3/4): ";
    cin >> choice;

    cout << "Enter first number: ";
    cin >> num1;

    cout << "Enter second number: ";
    cin >> num2;

    switch (choice) {
        case 1:
            cout << num1 << " + " << num2 << " = " << num1 + num2 << endl;
            break;
        case 2:
            cout << num1 << " - " << num2 << " = " << num1 - num2 << endl;
            break;
        case 3:
            cout << num1 << " * " << num2 << " = " << num1 * num2 << endl;
            break;
        case 4:
            if (num2 != 0) {
                cout << num1 << " / " << num2 << " = " << num1 / num2 << endl;
            } else {
                cout << "Error: Division by zero is not allowed." << endl;
            }
            break;
        default:
            cout << "Invalid choice." << endl;
    }

    return 0;
}
```

This program allows the user to choose from four basic arithmetic operations and performs the chosen operation on two input numbers. If the user chooses division and the second number is zero, it displays an error message to prevent division by zero.

**Calculating the Square of a Number in C++**
```cpp
#include <iostream>
using namespace std;

int main() {
    double num;
    cout << "Enter a number: ";
    cin >> num;
    double square = num * num;
    cout << "The square of " << num << " is: " << square << endl;
    return 0;
}
```
You can also write a function to calculate the square:
```cpp
#include <iostream>
using namespace std;

double calculateSquare(double num) {
    return num * num;
}

int main() {
    double num;
    cout << "Enter a number: ";
    cin >> num;
    double square = calculateSquare(num);
    cout << "The square of " << num << " is: " << square << endl;
    return 0;
}
```
To compile and run this code, save it in a file with a `.cpp` extension (e.g., `square.cpp`) and use a C++ compiler like `g++`:
```bash
g++ square.cpp -o square
./square
```
